const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const PROCESSING_FEE = 5;

export function processScenario(scenario: unknown): ScenarioOutput {
  const s = scenario as { steps: { op: string; items: { type: string }[] }[] };
  const results: StepResult[] = s.steps.map((step) => {
    const basePremium = step.items.reduce(
      (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
      0,
    );
    const withSurcharge = Math.ceil(basePremium * 1.1);
    const premium = withSurcharge + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

