  const input = scenario as Scenario;
  const results: StepResult[] = input.steps.map((step) => {
    const basePremium = calculateBasePremium(step.items);
    const premium = basePremium + Math.ceil(basePremium * 10 / 100) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

