import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should calculate base premium for a single sword (100G + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0].premium).toBe(115);
    });
    it("should calculate base premium for each main item type (amulet, staff, potion)", () => {
      const amuletResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(amuletResult.results[0].premium).toBe(71);

      const staffResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(staffResult.results[0].premium).toBe(93);

      const potionResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(potionResult.results[0].premium).toBe(49);
    });
    it("should sum base premiums for multiple different items plus processing fee", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0].premium).toBe(181);
    });
    it("should calculate base premium for a single component (25G + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "component", componentType: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0].premium).toBe(33);
    });
    it("should apply building block pricing for 3 alike components (60G instead of 75G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "component", componentType: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "component", componentType: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "component", componentType: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0].premium).toBe(71);
    });
    it.todo("should add 50% surcharge for cursed items");
    it.todo("should add 30% surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply both cursed and enchantment surcharges on the same item");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 10% initial assessment surcharge for first insurance");
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should round all amounts to whole G in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to highly enchanted items (>= 8) at 50%");
    it.todo("should fully reimburse damage to items made of dragon material");
    it.todo("should track remaining cap across multiple claims on the same policy");
  });

  describe("Scenario processing", () => {
    it.todo("should process a quote step and return premium");
    it.todo("should process a claim step referencing a prior quote and return payout and remainingCap");
  });
});

