interface Item {
  type: string;
  componentType?: string;
  cursed?: boolean;
}

interface Step {
  op: string;
  items: Item[];
}

interface Scenario {
  steps: Step[];
}

interface StepResult {
  premium?: number;
  payout?: number;
  remainingCap?: number;
}

interface ScenarioOutput {
  results: StepResult[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;
const BUILDING_BLOCK_SIZE = 3;

function calculateBasePremium(items: Item[]): number {
  let premium = 0;
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    if (item.type === "component" && item.componentType) {
      componentCounts[item.componentType] = (componentCounts[item.componentType] ?? 0) + 1;
    } else {
      let itemPremium = BASE_PREMIUMS[item.type] ?? 0;
      if (item.cursed) {
        itemPremium += Math.ceil(itemPremium * 50 / 100);
      }
      premium += itemPremium;
    }
  }

  for (const count of Object.values(componentCounts)) {
    const blocks = Math.floor(count / BUILDING_BLOCK_SIZE);
    const remainder = count % BUILDING_BLOCK_SIZE;
    premium += blocks * BUILDING_BLOCK_PREMIUM + remainder * COMPONENT_PREMIUM;
  }

  return premium;
}

export function processScenario(scenario: unknown): ScenarioOutput {
  const input = scenario as Scenario;
  const results: StepResult[] = input.steps.map((step) => {
    const basePremium = calculateBasePremium(step.items);
    const premium = basePremium + Math.ceil(basePremium * 10 / 100) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

