      isFirstQuote = false;
    }
    if (input.customer.yearsWithMHPCO >= 2) {
      premiumBeforeFee -= Math.floor(premiumBeforeFee * LOYALTY_DISCOUNT_PERCENT / 100);
    }
    const premium = premiumBeforeFee + PROCESSING_FEE;
    results.push({ premium });
  }
  return { results };
}

