function processClaim(step: Step, policy: { insuranceSum: number; remainingCap: number }): { payout: number; remainingCap: number } {
  let payout = 0;
  for (const damage of step.incident!.damages) {
    payout += Math.max(0, damage.amount - DEDUCTIBLE);
  }
  payout = Math.min(payout, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
}

export function processScenario(scenario: unknown): ScenarioOutput {
  const input = scenario as Scenario;
  const results: StepResult[] = [];
  const policies: { insuranceSum: number; remainingCap: number }[] = [];
  let isFirstQuote = true;
  for (let i = 0; i < input.steps.length; i++) {
    const step = input.steps[i];
    if (step.op === "quote") {
      const items = step.items!;
      results.push(processQuote(items, isFirstQuote, input.customer));
      const insuranceSum = calculateInsuranceSum(items);
      policies[i] = { insuranceSum, remainingCap: insuranceSum * 2 };
      isFirstQuote = false;
    } else if (step.op === "claim") {
      results.push(processClaim(step, policies[step.policy!]));
    }
  }
  return { results };
}

